import { buildColorRule } from './build-color-rule.js';
import { ColorToken } from '../../core/types/color-palette.js';
import type { ColorRuleProps } from '../../core/types/color-rule.js';
import type {
  CategoricalLegendColorMap,
  InternalTreeMapNode,
  LegendColorMap,
} from '../types/internal.js';
import { type NameAccessor } from '../types/treemap.js';

const getLeafColor = (
  node: InternalTreeMapNode,
  legendColorMap: LegendColorMap,
  colorRules?: ColorRuleProps[],
  defaultValueAccessor?: NameAccessor,
): ColorToken | undefined => {
  const ruleColor = buildColorRule(node, colorRules, defaultValueAccessor);
  return ruleColor
    ? { Default: ruleColor }
    : (legendColorMap as CategoricalLegendColorMap).get(node.name)?.color;
};

const getColoredLeafNodes = (
  nodes: InternalTreeMapNode[],
  legendColorMap: LegendColorMap,
  colorRules?: ColorRuleProps[],
  defaultValueAccessor?: NameAccessor,
) =>
  nodes.map((node) => ({
    ...node,
    color: getLeafColor(node, legendColorMap, colorRules, defaultValueAccessor),
  }));

/**
 * Function to apply colorPalette to the tree
 * @param rootNode - InternalTreeMapNode
 * @param legendColorMap - data structure for coloring the nodes
 * @param nameAccessor - targeted property on the leaf node
 * @param colorRules - raw color rules to apply
 * @returns - children array with applied colors
 */
export const getCategoricalColoredNodes = (
  rootNode: InternalTreeMapNode,
  legendColorMap: LegendColorMap,
  nameAccessor?: NameAccessor,
  colorRules?: ColorRuleProps[],
) => {
  const clusterNodes = rootNode.children ?? [];

  return clusterNodes.map((clusterNode) => ({
    ...clusterNode,
    ...(nameAccessor && {
      children: getColoredLeafNodes(
        clusterNode.children || [],
        legendColorMap,
        colorRules,
        nameAccessor,
      ),
    }),
    ...(!nameAccessor && {
      color: (legendColorMap as CategoricalLegendColorMap).get(clusterNode.name)
        ?.color,
      children: getColoredLeafNodes(
        clusterNode.children || [],
        legendColorMap,
        colorRules,
      ),
    }),
  }));
};
